head.b:skin:
/* ================================================================
   VOCES POR LA DIGNIDAD — v4
   Lenin Pérez Guzmán · Costa Rica
   ================================================================ */

/* ── TOKENS ─────────────────────────────────────────────────── */
:root {
  --ink:       #080e1d;
  --navy:      #0c1c38;
  --navy-mid:  #152d55;
  --navy-soft: #1c3a6e;
  --gold:      #c9973a;
  --gold-lt:   #e4b96a;
  --gold-pale: #fdf5e4;
  --cream:     #faf8f3;
  --white:     #ffffff;
  --muted:     #6b7280;
  --border:    #e2ddd5;
  --text:      #1f2937;
  --text-lt:   #4b5563;
  --font-d: 'Playfair Display', Georgia, serif;
  --font-s: 'DM Sans', 'Segoe UI', system-ui, sans-serif;
  --hdr: 68px;
  --max: 1120px;
  --prose: 760px;
  --ease: .22s cubic-bezier(.4,0,.2,1);
  --sh: 0 2px 12px rgba(8,14,29,.09);
  --sh-lg: 0 16px 48px rgba(8,14,29,.15);
}

/* ── RESET ──────────────────────────────────────────────────── */
*,::before,::after { box-sizing: border-box; margin: 0; padding: 0; }
html { font-size: 16px; scroll-behavior: smooth; }
body {
  font-family: var(--font-s);
  color: var(--text);
  background: var(--cream);
  line-height: 1.65;
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}
img { max-width: 100%; height: auto; display: block; }
a { color: inherit; text-decoration: none; transition: color var(--ease); }
ul, ol { list-style: none; }
button { font: inherit; cursor: pointer; background: none; border: none; }
#navbar-iframe, .navbar-iframe-container { display: none !important; height: 0 !important; }
.blogger-post-edit-link { display: none !important; }

/* ── ACCESSIBILITY ──────────────────────────────────────────── */
.skip {
  position: absolute; top: -200%; left: 0;
  padding: .5rem 1.5rem; background: var(--navy);
  color: var(--white); font-weight: 600; font-size: .85rem;
  z-index: 9999; border-radius: 0 0 6px 0; transition: top .2s;
}
.skip:focus { top: 0; }
:focus-visible { outline: 2px solid var(--gold); outline-offset: 3px; border-radius: 3px; }

/* ── LAYOUT ─────────────────────────────────────────────────── */
.wrap { width: 100%; max-width: var(--max); margin-inline: auto; padding-inline: 1.5rem; }
.prose { width: 100%; max-width: var(--prose); margin-inline: auto; padding-inline: 1.5rem; }

/* ── HEADER ─────────────────────────────────────────────────── */
.hdr {
  position: sticky; top: 0; z-index: 300;
  height: var(--hdr);
  background: rgba(8,14,29,.97);
  backdrop-filter: blur(20px);
  border-bottom: 1px solid rgba(201,151,58,.18);
}
.hdr-in {
  max-width: var(--max); margin-inline: auto; padding-inline: 1.5rem;
  height: 100%; display: flex; align-items: center;
  justify-content: space-between; gap: 1.5rem;
}
/* Logo */
.logo { display: flex; flex-direction: column; line-height: 1.1; }
.logo-m { font-family: var(--font-d); font-weight: 900; font-size: 1.1rem; color: var(--white); letter-spacing: -.02em; }
.logo-s { font-size: .62rem; color: rgba(255,255,255,.38); letter-spacing: .1em; text-transform: uppercase; margin-top: .2rem; }
.logo:hover .logo-m { color: var(--gold-lt); }

/* Nav desktop */
.nav-d { display: flex; align-items: center; gap: .25rem; }
.nav-d a {
  display: block; padding: .4rem 1rem;
  font-size: .78rem; font-weight: 500; letter-spacing: .05em; text-transform: uppercase;
  color: rgba(255,255,255,.58); border-radius: 4px;
  transition: color var(--ease), background var(--ease);
}
.nav-d a:hover, .nav-d a:focus { color: var(--white); background: rgba(255,255,255,.07); }

/* Social icons header */
.hdr-social { display: flex; align-items: center; gap: .5rem; }
.hdr-social a {
  display: flex; align-items: center; justify-content: center;
  width: 32px; height: 32px; border-radius: 6px;
  border: 1px solid rgba(255,255,255,.15);
  color: rgba(255,255,255,.55);
  transition: all var(--ease);
}
.hdr-social a:hover { color: var(--gold-lt); border-color: rgba(201,151,58,.5); background: rgba(201,151,58,.08); }
.hdr-social svg { width: 15px; height: 15px; fill: currentColor; }

/* Hamburger */
.burger {
  display: none; flex-direction: column; justify-content: center; gap: 5px;
  width: 38px; height: 38px; padding: .45rem;
  border: 1px solid rgba(255,255,255,.18); border-radius: 5px;
}
.burger:hover { border-color: rgba(201,151,58,.5); }
.bar { display: block; width: 100%; height: 1.5px; background: rgba(255,255,255,.75); border-radius: 2px; transition: transform .25s, opacity .25s; }
.burger[aria-expanded=true] .bar:nth-child(1) { transform: translateY(6.5px) rotate(45deg); }
.burger[aria-expanded=true] .bar:nth-child(2) { opacity: 0; }
.burger[aria-expanded=true] .bar:nth-child(3) { transform: translateY(-6.5px) rotate(-45deg); }

/* Mobile nav */
.nav-m {
  display: none; position: fixed; inset: var(--hdr) 0 0;
  background: rgba(8,14,29,.98); backdrop-filter: blur(20px);
  flex-direction: column; padding: 2rem 1.5rem; gap: .5rem;
  overflow-y: auto; z-index: 299;
}
.nav-m.open { display: flex; }
.nav-m a { font-size: 1.2rem; font-weight: 500; color: rgba(255,255,255,.7); padding: .9rem 1rem; border-radius: 8px; transition: all var(--ease); }
.nav-m a:hover { color: var(--white); background: rgba(255,255,255,.07); }
.nav-m-social { display: flex; gap: .75rem; padding: 1.5rem 1rem 0; border-top: 1px solid rgba(255,255,255,.08); margin-top: 1rem; }
.nav-m-social a { display: flex; align-items: center; gap: .5rem; font-size: .85rem; color: rgba(255,255,255,.45); }
.nav-m-social a:hover { color: var(--gold-lt); }
.nav-m-social svg { width: 16px; height: 16px; fill: currentColor; }

/* ── HERO ───────────────────────────────────────────────────── */
.hero {
  position: relative; overflow: hidden; isolation: isolate;
  background: var(--navy);
  padding: 6rem 1.5rem 5rem;
}
.hero::before {
  content: ''; position: absolute; inset: 0; z-index: 0;
  background:
    radial-gradient(ellipse 90% 70% at 75% 40%, rgba(201,151,58,.13) 0%, transparent 65%),
    radial-gradient(ellipse 60% 90% at 5% 90%, rgba(21,45,85,.9) 0%, transparent 55%);
}
.hero::after {
  content: ''; position: absolute; inset: 0; z-index: 0;
  background-image: linear-gradient(rgba(201,151,58,.035) 1px, transparent 1px),
    linear-gradient(90deg, rgba(201,151,58,.035) 1px, transparent 1px);
  background-size: 56px 56px;
}
.hero-in { position: relative; z-index: 1; max-width: 700px; }
.hero-kicker {
  display: inline-flex; align-items: center; gap: .75rem;
  font-size: .7rem; font-weight: 700; letter-spacing: .15em; text-transform: uppercase;
  color: var(--gold); margin-bottom: 1.5rem;
}
.hero-kicker::before { content: ''; display: block; width: 28px; height: 1px; background: var(--gold); }
.hero h1 {
  font-family: var(--font-d); font-weight: 900;
  font-size: clamp(2.8rem, 7vw, 5.2rem);
  color: var(--white); line-height: 1.02; letter-spacing: -.035em;
  margin-bottom: 1.5rem;
}
.hero h1 em { font-style: italic; color: var(--gold-lt); }
.hero-sub {
  font-size: 1.08rem; color: rgba(255,255,255,.62);
  line-height: 1.8; max-width: 540px; margin-bottom: 2.5rem;
}
.hero-ctas { display: flex; flex-wrap: wrap; gap: 1rem; }

/* ── BOTONES ────────────────────────────────────────────────── */
.btn {
  display: inline-flex; align-items: center; gap: .5rem;
  padding: .7rem 1.6rem; font-family: var(--font-s); font-size: .82rem;
  font-weight: 600; letter-spacing: .02em; border-radius: 5px;
  border: 1.5px solid transparent; transition: all var(--ease);
}
.btn-gold { background: var(--gold); color: var(--navy); border-color: var(--gold); }
.btn-gold:hover, .btn-gold:focus { background: var(--gold-lt); border-color: var(--gold-lt); color: var(--navy); }
.btn-ghost { color: rgba(255,255,255,.78); border-color: rgba(255,255,255,.25); }
.btn-ghost:hover, .btn-ghost:focus { color: var(--white); border-color: rgba(255,255,255,.6); background: rgba(255,255,255,.07); }
.btn-outline { color: var(--navy); border-color: var(--border); background: var(--white); }
.btn-outline:hover, .btn-outline:focus { border-color: var(--gold); color: var(--gold); }
.btn-navy { background: var(--navy); color: var(--white); border-color: var(--navy); }
.btn-navy:hover, .btn-navy:focus { background: var(--navy-mid); border-color: var(--navy-mid); color: var(--white); }

/* ── SECTION CHROME ─────────────────────────────────────────── */
.sec-eyebrow {
  display: flex; align-items: center; gap: 1rem;
  font-size: .68rem; font-weight: 700; letter-spacing: .15em; text-transform: uppercase;
  color: var(--gold); margin-bottom: 1.5rem;
}
.sec-eyebrow::after { content: ''; flex: 1; height: 1px; background: var(--border); }
.sec-h { font-family: var(--font-d); font-weight: 900; font-size: clamp(1.6rem,3.5vw,2.4rem); color: var(--ink); letter-spacing: -.025em; line-height: 1.15; }

/* ── ARTÍCULOS / FILTROS ────────────────────────────────────── */
.sec-art { padding: 4rem 0 0; }
.filters { display: flex; flex-wrap: wrap; gap: .5rem; margin: 1.5rem 0 3rem; }
.ftag {
  display: inline-block; padding: .35rem 1rem;
  font-size: .76rem; font-weight: 600; letter-spacing: .03em;
  border: 1.5px solid var(--border); border-radius: 100px;
  color: var(--text-lt); background: var(--white);
  transition: all var(--ease);
}
.ftag:hover, .ftag:focus { border-color: var(--gold); color: var(--gold); }

/* ── CARDS GRID ─────────────────────────────────────────────── */
.cards-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(310px, 1fr));
  gap: 1.5rem;
  padding-bottom: 5rem;
}
.card {
  background: var(--white); border: 1px solid var(--border); border-radius: 14px;
  display: flex; flex-direction: column; overflow: hidden;
  transition: box-shadow var(--ease), transform var(--ease);
  position: relative;
}
.card::after {
  content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px;
  background: linear-gradient(90deg, var(--gold), var(--gold-lt));
  transform: scaleX(0); transform-origin: left; transition: transform var(--ease);
}
.card:hover { box-shadow: var(--sh-lg); transform: translateY(-5px); }
.card:hover::after { transform: scaleX(1); }
.card-body { padding: 2rem; flex: 1; display: flex; flex-direction: column; }
.card-meta { display: flex; align-items: center; gap: .75rem; margin-bottom: 1.25rem; flex-wrap: wrap; }
.card-date { font-size: .72rem; color: var(--muted); }
.c-tag {
  display: inline-block; font-size: .65rem; font-weight: 700; letter-spacing: .06em;
  text-transform: uppercase; color: var(--navy-soft); background: rgba(28,58,110,.07);
  padding: 2px 10px; border-radius: 100px;
  transition: background var(--ease), color var(--ease);
}
.c-tag:hover { background: var(--navy); color: var(--white); }
.card-title {
  font-family: var(--font-d); font-weight: 700; font-size: 1.18rem;
  line-height: 1.3; letter-spacing: -.01em; color: var(--ink);
  margin-bottom: 1rem; flex: 1;
}
.card-title a { color: inherit; }
.card-title a:hover { color: var(--navy-soft); }
.card-excerpt { font-size: .87rem; color: var(--text-lt); line-height: 1.72; margin-bottom: 1.5rem; }
.card-cta {
  display: inline-flex; align-items: center; gap: .4rem;
  font-size: .75rem; font-weight: 700; letter-spacing: .05em; text-transform: uppercase;
  color: var(--gold);
}
.card-cta::after { content: '→'; transition: transform var(--ease); }
.card-cta:hover::after { transform: translateX(4px); }

/* Pager */
.pager { display: flex; gap: 1rem; justify-content: center; padding: 1rem 0 5rem; }

/* ── QUOTE BAND ─────────────────────────────────────────────── */
.q-band {
  background: var(--navy); padding: 5rem 1.5rem;
  position: relative; overflow: hidden;
}
.q-band::before {
  content: ''; position: absolute; inset: 0;
  background: radial-gradient(ellipse 70% 100% at 100% 50%, rgba(201,151,58,.1), transparent);
}
.q-in { max-width: 680px; margin-inline: auto; text-align: center; position: relative; z-index: 1; }
.q-mark { font-family: var(--font-d); font-size: 9rem; line-height: .55; color: rgba(201,151,58,.15); display: block; font-style: italic; margin-bottom: 1.5rem; }
.q-text { font-family: var(--font-d); font-style: italic; font-weight: 700; font-size: clamp(1.4rem,3vw,2rem); color: var(--white); line-height: 1.45; margin-bottom: 1.25rem; }
.q-author { font-size: .72rem; color: var(--gold); letter-spacing: .12em; text-transform: uppercase; font-weight: 600; }

/* ── SOBRE / BIO ────────────────────────────────────────────── */
.bio-band { background: var(--white); border-top: 1px solid var(--border); padding: 5rem 1.5rem; }
.bio-grid { max-width: var(--max); margin-inline: auto; display: grid; grid-template-columns: 5fr 4fr; gap: 5rem; align-items: start; }
.bio-eyebrow { font-size: .68rem; font-weight: 700; letter-spacing: .15em; text-transform: uppercase; color: var(--gold); margin-bottom: 1.25rem; }
.bio-h { font-family: var(--font-d); font-weight: 900; font-size: clamp(1.6rem,3vw,2.2rem); color: var(--ink); letter-spacing: -.025em; line-height: 1.1; margin-bottom: 1.75rem; }
.bio-text p { color: var(--text-lt); line-height: 1.85; margin-bottom: 1.1rem; font-size: .97rem; }
.bio-text p:last-child { margin-bottom: 0; }
.bio-cta { margin-top: 2rem; }

/* Bio highlights */
.bio-highlights { display: flex; flex-direction: column; gap: 1rem; }
.bio-card {
  background: var(--cream); border: 1px solid var(--border); border-radius: 12px;
  padding: 1.25rem 1.5rem; display: flex; gap: 1rem; align-items: flex-start;
}
.bio-icon { font-size: 1.4rem; flex-shrink: 0; margin-top: .1rem; }
.bio-card h3 { font-family: var(--font-d); font-size: .95rem; font-weight: 700; color: var(--ink); margin-bottom: .3rem; }
.bio-card p { font-size: .8rem; color: var(--muted); line-height: 1.6; }

/* ── TEMAS ──────────────────────────────────────────────────── */
.topics-band { background: var(--cream); border-top: 1px solid var(--border); padding: 4rem 1.5rem 5rem; }
.topics-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(210px,1fr)); gap: 1rem; margin-top: 2rem; }
.topic-card {
  background: var(--white); border: 1px solid var(--border); border-radius: 12px;
  padding: 1.75rem 1.5rem; text-align: center;
  transition: box-shadow var(--ease), transform var(--ease), border-color var(--ease);
}
.topic-card:hover { box-shadow: var(--sh); transform: translateY(-3px); border-color: var(--gold); }
.topic-icon { font-size: 2rem; display: block; margin-bottom: 1rem; }
.topic-card h3 { font-family: var(--font-d); font-size: .98rem; font-weight: 700; color: var(--ink); margin-bottom: .5rem; }
.topic-card p { font-size: .8rem; color: var(--muted); line-height: 1.65; }

/* ── PAGE HEADER (etiqueta, búsqueda, página estática) ──────── */
.page-hdr {
  background: var(--navy); padding: 3.5rem 1.5rem 4rem;
  border-bottom: 3px solid var(--gold);
}
.page-hdr-in { max-width: var(--prose); margin-inline: auto; }
.page-kicker { font-size: .68rem; font-weight: 700; letter-spacing: .15em; text-transform: uppercase; color: var(--gold); margin-bottom: 1rem; }
.page-hdr h1 { font-family: var(--font-d); font-weight: 900; font-size: clamp(1.8rem,4vw,2.8rem); color: var(--white); letter-spacing: -.025em; line-height: 1.1; }

/* ── POST ───────────────────────────────────────────────────── */
.post-hdr {
  background: var(--navy); padding: 3.5rem 1.5rem 4.5rem;
  position: relative; overflow: hidden;
}
.post-hdr::before {
  content: ''; position: absolute; inset: 0;
  background: radial-gradient(ellipse 70% 80% at 85% 20%, rgba(201,151,58,.1), transparent);
}
.post-hdr-in { max-width: var(--prose); margin-inline: auto; position: relative; z-index: 1; }
.breadcrumb { display: flex; flex-wrap: wrap; gap: .4rem; align-items: center; margin-bottom: 2rem; font-size: .72rem; }
.breadcrumb li:not(:last-child)::after { content: '›'; margin-left: .4rem; color: rgba(255,255,255,.28); }
.breadcrumb a { color: rgba(255,255,255,.48); }
.breadcrumb a:hover { color: var(--gold); }
.breadcrumb li:last-child { color: rgba(255,255,255,.35); }
.post-tags { display: flex; flex-wrap: wrap; gap: .5rem; margin-bottom: 1.5rem; }
.p-tag {
  display: inline-block; font-size: .67rem; font-weight: 700; letter-spacing: .08em; text-transform: uppercase;
  color: var(--gold); background: rgba(201,151,58,.12); border: 1px solid rgba(201,151,58,.28);
  padding: 3px 12px; border-radius: 100px;
}
.p-tag:hover { background: rgba(201,151,58,.22); }
.post-hdr h1 { font-family: var(--font-d); font-weight: 900; font-size: clamp(1.9rem,5vw,3.2rem); color: var(--white); line-height: 1.08; letter-spacing: -.03em; margin-bottom: 1.5rem; }
.post-byline { font-size: .8rem; color: rgba(255,255,255,.42); display: flex; gap: 1rem; flex-wrap: wrap; align-items: center; }
.post-byline a { color: rgba(255,255,255,.58); }
.post-byline a:hover { color: var(--gold); }
.post-sep { color: rgba(255,255,255,.2); }

/* Post body */
.post-body-wrap { padding: 4rem 1.5rem 3rem; }
.post-body { max-width: var(--prose); margin-inline: auto; }
.post-body p { font-size: 1.05rem; line-height: 1.9; color: var(--text); margin-bottom: 1.5rem; }
.post-body h2 { font-family: var(--font-d); font-weight: 900; font-size: 1.65rem; color: var(--ink); letter-spacing: -.02em; margin: 3rem 0 1.25rem; padding-bottom: 1rem; border-bottom: 1px solid var(--border); line-height: 1.2; }
.post-body h3 { font-family: var(--font-d); font-size: 1.25rem; font-weight: 700; color: var(--navy); margin: 2rem 0 1rem; }
.post-body blockquote { margin: 2.5rem 0; padding: 1.5rem 2rem 1.5rem 1.5rem; border-left: 3px solid var(--gold); background: var(--gold-pale); border-radius: 0 10px 10px 0; }
.post-body blockquote p { font-family: var(--font-d); font-style: italic; font-size: 1.1rem; color: var(--navy); line-height: 1.65; margin: 0; }
.post-body ul, .post-body ol { padding-left: 1.5rem; margin-bottom: 1.5rem; }
.post-body ul li { list-style: disc; }
.post-body ol li { list-style: decimal; }
.post-body li { font-size: 1rem; line-height: 1.8; color: var(--text); margin-bottom: .75rem; }
.post-body a { color: var(--navy-soft); font-weight: 500; text-decoration: underline; text-underline-offset: 3px; }
.post-body a:hover { color: var(--gold); }
.post-body img { border-radius: 10px; margin: 2rem auto; box-shadow: var(--sh); }

/* Post signature */
.post-sig {
  display: flex; gap: 1.25rem; align-items: center;
  margin-top: 4rem; padding: 1.75rem; border-radius: 14px;
  background: var(--cream); border: 1px solid var(--border);
}
.sig-av {
  width: 52px; height: 52px; border-radius: 50%; flex-shrink: 0;
  background: linear-gradient(135deg, var(--navy), var(--navy-soft));
  display: flex; align-items: center; justify-content: center;
  font-family: var(--font-d); font-weight: 900; font-size: 1rem; color: var(--gold-lt);
}
.sig-name { font-family: var(--font-d); font-weight: 700; font-size: .97rem; color: var(--ink); margin-bottom: .25rem; }
.sig-role { font-size: .78rem; color: var(--muted); line-height: 1.55; }

/* Post share (redes sociales) */
.post-share { padding: 1.5rem; background: var(--white); border-top: 1px solid var(--border); }
.post-share-in { max-width: var(--prose); margin-inline: auto; display: flex; align-items: center; gap: 1.25rem; flex-wrap: wrap; }
.share-label { font-size: .72rem; font-weight: 700; letter-spacing: .1em; text-transform: uppercase; color: var(--muted); }
.share-links { display: flex; gap: .6rem; }
.share-btn {
  display: flex; align-items: center; gap: .4rem; padding: .4rem .9rem;
  font-size: .75rem; font-weight: 600; border-radius: 6px; border: 1px solid var(--border);
  color: var(--text-lt); background: var(--cream); transition: all var(--ease);
}
.share-btn svg { width: 14px; height: 14px; fill: currentColor; }
.share-btn:hover { background: var(--navy); color: var(--white); border-color: var(--navy); }

/* Back link */
.post-back { background: var(--cream); border-top: 1px solid var(--border); padding: 1.5rem; }
.post-back-in { max-width: var(--prose); margin-inline: auto; }
.back-lnk {
  display: inline-flex; align-items: center; gap: .5rem;
  font-size: .8rem; font-weight: 600; color: var(--navy); transition: color var(--ease);
}
.back-lnk::before { content: '←'; transition: transform var(--ease); }
.back-lnk:hover { color: var(--gold); }
.back-lnk:hover::before { transform: translateX(-4px); }

/* ── STATIC PAGE ────────────────────────────────────────────── */
.static-body { padding: 4rem 1.5rem 5rem; }
.static-body .prose h2 { font-family: var(--font-d); font-size: 1.35rem; font-weight: 700; color: var(--ink); margin: 2.5rem 0 1rem; padding-top: 2rem; border-top: 1px solid var(--border); }
.static-body .prose h2:first-child { margin-top: 0; padding-top: 0; border-top: none; }
.static-body .prose p { font-size: 1rem; color: var(--text); line-height: 1.85; margin-bottom: 1.25rem; }
.static-body .prose ul { padding-left: 1.5rem; margin-bottom: 1.25rem; }
.static-body .prose li { list-style: disc; color: var(--text); line-height: 1.8; margin-bottom: .75rem; }
.static-body .prose strong { color: var(--ink); font-weight: 600; }

/* ── FOOTER ─────────────────────────────────────────────────── */
.ftr { background: var(--ink); color: rgba(255,255,255,.5); padding: 4rem 1.5rem 2rem; margin-top: auto; }
.ftr-grid {
  max-width: var(--max); margin-inline: auto;
  display: grid; grid-template-columns: 2.5fr 1fr 1fr 2fr; gap: 3rem;
  padding-bottom: 3rem; border-bottom: 1px solid rgba(255,255,255,.07);
  margin-bottom: 2rem;
}
.ftr-brand-name { font-family: var(--font-d); font-weight: 900; font-size: 1.1rem; color: var(--white); margin-bottom: .5rem; }
.ftr-divider { width: 36px; height: 2px; background: var(--gold); border-radius: 2px; margin: 1rem 0; }
.ftr-desc { font-size: .8rem; color: rgba(255,255,255,.38); line-height: 1.75; max-width: 260px; }
.ftr-social { display: flex; gap: .6rem; margin-top: 1.5rem; flex-wrap: wrap; }
.ftr-soc-btn {
  display: flex; align-items: center; justify-content: center;
  width: 34px; height: 34px; border-radius: 7px;
  border: 1px solid rgba(255,255,255,.12); color: rgba(255,255,255,.45);
  transition: all var(--ease);
}
.ftr-soc-btn:hover { color: var(--gold-lt); border-color: rgba(201,151,58,.45); background: rgba(201,151,58,.08); }
.ftr-soc-btn svg { width: 15px; height: 15px; fill: currentColor; }
.ftr-col h4 { font-size: .65rem; font-weight: 700; letter-spacing: .12em; text-transform: uppercase; color: rgba(255,255,255,.3); margin-bottom: 1rem; }
.ftr-col ul { display: flex; flex-direction: column; gap: .75rem; }
.ftr-col a { font-size: .83rem; color: rgba(255,255,255,.45); transition: color var(--ease); }
.ftr-col a:hover { color: var(--gold-lt); }
.ftr-disclaimer { font-size: .77rem; color: rgba(255,255,255,.28); line-height: 1.8; }
.ftr-bottom { max-width: var(--max); margin-inline: auto; display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 1rem; }
.ftr-copy { font-size: .73rem; color: rgba(255,255,255,.22); }
.ftr-badge { font-size: .65rem; color: rgba(255,255,255,.18); letter-spacing: .08em; text-transform: uppercase; }

/* ── RESPONSIVE ─────────────────────────────────────────────── */
@media (max-width: 900px) {
  .bio-grid { grid-template-columns: 1fr; gap: 3rem; }
  .ftr-grid { grid-template-columns: 1fr 1fr; gap: 2rem; }
}
@media (max-width: 768px) {
  .burger { display: flex; }
  .nav-d, .hdr-social { display: none; }
  .hero { padding: 4rem 1.5rem; }
  .ftr-grid { grid-template-columns: 1fr; gap: 2rem; }
  .ftr-bottom { flex-direction: column; text-align: center; }
  .post-sig { flex-direction: column; text-align: center; }
}
@media (max-width: 520px) {
  .cards-grid { grid-template-columns: 1fr; }
  .topics-grid { grid-template-columns: 1fr 1fr; }
  .hero-ctas { flex-direction: column; }
  .btn { justify-content: center; text-align: center; }
}
@media print {
  .hdr, .hero-ctas, .ftr, .post-back, .post-share { display: none; }
  body { color: #000; background: #fff; }
}

body.script:
//
(function(){
'use strict';

/* Año */
var yr = document.getElementById('yr');
if(yr) yr.textContent = new Date().getFullYear();

/* Hamburger */
var burger = document.getElementById('burger');
var navM   = document.getElementById('nav-m');
if(burger && navM){
  function openNav(){  navM.classList.add('open');    burger.setAttribute('aria-expanded','true');  document.body.style.overflow='hidden'; }
  function closeNav(){ navM.classList.remove('open'); burger.setAttribute('aria-expanded','false'); document.body.style.overflow=''; }
  burger.addEventListener('click', function(){ burger.getAttribute('aria-expanded')==='true' ? closeNav() : openNav(); });
  document.addEventListener('keydown', function(e){ if(e.key==='Escape') closeNav(); });
  navM.addEventListener('click', function(e){ if(e.target.tagName==='A') closeNav(); });
  window.addEventListener('resize', function(){ if(window.innerWidth > 768) closeNav(); });
}

/* Marcar filtro activo por URL */
var url = window.location.href;
document.querySelectorAll('.ftag').forEach(function(tag){
  var href = tag.getAttribute('href') || '';
  if(href.indexOf('label/') > -1){
    var lbl = decodeURIComponent((href.split('label/')[1] || ''));
    if(lbl && url.indexOf(encodeURIComponent(lbl)) > -1){
      document.querySelectorAll('.ftag').forEach(function(t){ t.style.background=''; t.style.borderColor=''; t.style.color=''; });
      tag.style.background = '#0c1c38';
      tag.style.borderColor = '#0c1c38';
      tag.style.color = '#ffffff';
    }
  }
});

/* Skip link */
var skip = document.querySelector('.skip');
if(skip){
  skip.addEventListener('click', function(e){
    var t = document.getElementById('content');
    if(t){ e.preventDefault(); t.setAttribute('tabindex','-1'); t.focus(); t.addEventListener('blur', function(){ t.removeAttribute('tabindex'); },{once:true}); }
  });
}

})();
//
